+"use client";
+
+import { useRouter, useSearchParams } from "next/navigation";
+import { useState, useRef, useEffect } from "react";
+import { Search, X } from "lucide-react";
+import { Input } from "@/components/ui/input";
+import { Button } from "@/components/ui/button";
+
+/** Standalone search input for the /search page (used on all viewports). */
+export function SearchInput({ initialQuery }: { initialQuery: string }) {
+  const router = useRouter();
+  const searchParams = useSearchParams();
+  const [value, setValue] = useState(initialQuery);
+  const inputRef = useRef<HTMLInputElement>(null);
+
+  // Sync when query param changes externally
+  useEffect(() => {
+    setValue(searchParams.get("q") ?? "");
+  }, [searchParams]);
+
+  // Auto-focus on mount when there's no query
+  useEffect(() => {
+    if (!initialQuery) {
+      inputRef.current?.focus();
+    }
+  }, [initialQuery]);
+
+  function handleSubmit(e: React.FormEvent) {
+    e.preventDefault();
+    const trimmed = value.trim();
+    if (trimmed) {
+      router.push(`/search?q=${encodeURIComponent(trimmed)}`);
+    }
+  }
+
+  return (
+    <form onSubmit={handleSubmit} className="relative mt-4 max-w-lg">
+      <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
+      <Input
+        ref={inputRef}
+        type="search"
+        placeholder="Search products…"
+        className="h-11 pl-10 pr-10 text-base"
+        value={value}
+        onChange={(e) => setValue(e.target.value)}
+      />
+      {value && (
+        <Button
+          type="button"
+          variant="ghost"
+          size="icon"
+          className="absolute right-1 top-1/2 h-8 w-8 -translate-y-1/2"
+          onClick={() => {
+            setValue("");
+            inputRef.current?.focus();
+          }}
+        >
+          <X className="h-4 w-4" />
+        </Button>
+      )}
+    </form>
+  );
+}

